  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Ans Behrns/ ne aistmir- \nsti mannus Bauslibu/ \nbet lai tawa Sirđs pa- \nturr mannus Bauslus.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Jo tee dohs tew ilgu Dsh- \nwoschann/ wehelu Muhschu un \nMeeru.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Ka Schehlastiba un Patee- \nfiba tewi ne atstabhj/ apseen tohs \nap taivu Rafiu/ un eeraksti tohs \nus to Galdu tawas Sirđs.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tad tu Schehlastibu un \nismahzitu Prahtu atrasti Dee- \nwa un Zilweku Azzis.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Pataujees us to KUNgu \nno wiſſas tawas Sirđs/ un ne \npataujees us tawu Gudrumu.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Atsibsti winnu wiſſôs ta- \nwôs Zelfôs/ tad darrihs wiſsch \ntawus Gabjuinus pareisus.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Ne eſſi gudrs tawas Az- \nzis/ bthstees to KUNGU/ un at- \nlahpees no Launa.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Ta buhs weena Ahrtes \nSahle preeſſch tawas Nabbas/ \nun Smadsnes preeſſch taweem \nKanleem.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Gohda to KUNGU no ta- \nwas Mantas/ un no teem Pir- \nmajeem wiſſa/ fo tu eedabhu.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Tad tapst tawi Schſuhni\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Mans Behrns/ ne at- \nmett to Pamahzischanu ta KUN- \nGA/ un lai winna Pahrmahzi- \nschana tew ne reebjahs.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Jo kuxxu tas KUNGS \nmihti turr/ to pahrimahza wiſsch/ \ntit ka weens Tehws to Dehlu/ \npee ka tam labs Brahts irr.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Swehtigs irr tas Zil- \nweks/ kas Gudribu atrohd/ un \ntas Zilweks/ kas Sapraschanu \needabhu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Jo tas irr labbaki fahrt \nwinnas prezzetees/ ne ka fahrt \nSudrabu/ un winnas Augti \n(irr labbafee) ne ka Selts.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Winna irr dahrgaka ne \nka Pehrles/ un wiſſ/ fo tu war- \nretu eegrbbetees/ ne irr ar tahs \nlihdsinajama.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Ilga Dshwoschana irr \npee winnas labbas Rohkas/ un \npee winnas kreifas Rohkas irr \nBaggatiba un Gohds.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Winnas Zelfi irr jauki \nZelfi/ un wiſſi winnas Gabju- \nmi ter Meers.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Winna irr weens Rohks \ntahs Dshwibas teem/ kas win- \nnu takampj/ un kas winnu stip- \nri turr/ tas irr lainigs.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Tas KUNGS irr zaur \nGudribu to Seimmi dibbinajs/ \nar Sapratchanu irr wiſsch tahs \nDebbefis fataiſijs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Zaur winna Siunascha- \nnu irr tee Besdibbini pahrdalli- \nHbbbbh ti/\n"
    }
  ],
